PyTypeObject* DoInitWrapperUserWidget(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperUserWidgetType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperUserWidgetPyMethodDefs;
	PyType->tp_getset = FUPyWrapperUserWidgetGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperUserWidget(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(UUserWidget::StaticClass(), DoInitWrapperUserWidget);
}

FUPyWrapperUserWidget* UPyIsUserWidget(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperUserWidgetType))
	{
		return (FUPyWrapperUserWidget*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, UUserWidget*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperUserWidget* PyUserWidget = UPyIsUserWidget(PyObj))
		{
			if (!FUPyWrapperObjectBase::ValidateInternalState(PyUserWidget))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyUserWidget->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'UUserWidget'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
